parameters.jsCode:
// Build evaluation prompt
const draft = $('Parse Draft & Build Blocks').first().json;
const cleanDraft = draft.cleanDraft;

const evalSystemPrompt = `Du bist ein strenger Content-Evaluator für T-0. Bewerte den folgenden Blogpost-Entwurf.

Bewerte jede Dimension von 1 bis 5:
1. Clarity (1.0x) - Verständlich? Keine unerklärten Fachbegriffe?
2. Structure (1.0x) - Progressive disclosure? Scannbar?
3. Accuracy (1.5x) - Fakten korrekt? Quellen zitiert?
4. Credibility (1.5x) - Show the work? Earned confidence?
5. Engagement (1.0x) - Starker Einstieg? Hält Aufmerksamkeit?
6. Voice (1.0x) - Klingt wie T-0? Starke Meinungen? Du-Form?
7. Actionability (1.0x) - Leser weiß was zu tun ist?

Composite = Clarity*1 + Structure*1 + Accuracy*1.5 + Credibility*1.5 + Engagement*1 + Voice*1 + Actionability*1 (max 40)

Tiers: Excellent (34-40), Good (28-33), Acceptable (22-27), Below Standard (16-21), Poor (<16)

GATE: Voice < 4 = BLOCKED. Any dimension < 3 = BLOCKED.

Antworte NUR als JSON.`;

return [{
  json: {
    pageId: draft.pageId,
    contentType: draft.contentType,
    cleanDraft,
    evalSystemPrompt,
    evalUserPrompt: `Bewerte diesen Blogpost-Entwurf:\n\n${cleanDraft.substring(0, 10000)}`
  }
}];

// Apply evaluation gate rules and determine status
let evalData;
try {
  evalData = $('Build Evaluation Prompt').first().json;
} catch(e) {
  evalData = $('B: Build Re-Eval Prompt').first().json;
}
const evalResult = $input.first().json;

// Extract scores from agent output (structured output parser returns an object)
let scores;
if (typeof evalResult.output === 'object' && evalResult.output !== null) {
  scores = evalResult.output;
} else if (typeof evalResult.output === 'string') {
  try { scores = JSON.parse(evalResult.output); } catch(e) {
    const jsonMatch = evalResult.output.match(/\{[\s\S]*\}/);
    scores = jsonMatch ? JSON.parse(jsonMatch[0]) : {};
  }
} else {
  scores = evalResult;
}

const clarity = scores.clarity?.score || 0;
const structure = scores.structure?.score || 0;
const accuracy = scores.accuracy?.score || 0;
const credibility = scores.credibility?.score || 0;
const engagement = scores.engagement?.score || 0;
const voice = scores.voice?.score || 0;
const actionability = scores.actionability?.score || 0;

const composite = clarity*1 + structure*1 + accuracy*1.5 + credibility*1.5 + engagement*1 + voice*1 + actionability*1;

let qualityTier = "Poor";
if (composite >= 34) qualityTier = "Excellent";
else if (composite >= 28) qualityTier = "Good";
else if (composite >= 22) qualityTier = "Acceptable";
else if (composite >= 16) qualityTier = "Below Standard";

// Gate rules
let newStatus = "Draft";
let blocked = false;
let blockReason = "";

if (voice < 4) {
  blocked = true;
  blockReason = "Voice score below minimum threshold (4). Constitutional principle: T-0 Voice ist nicht verhandelbar.";
} else if (clarity < 3 || structure < 3 || accuracy < 3 || credibility < 3 || engagement < 3 || actionability < 3) {
  blocked = true;
  const low = [];
  if (clarity < 3) low.push("Clarity");
  if (structure < 3) low.push("Structure");
  if (accuracy < 3) low.push("Accuracy");
  if (credibility < 3) low.push("Credibility");
  if (engagement < 3) low.push("Engagement");
  if (actionability < 3) low.push("Actionability");
  blockReason = `Dimensions below minimum (3): ${low.join(", ")}`;
}

if (!blocked && composite >= 28) {
  newStatus = "Pre Review";
}

const evalNotes = `Top: ${scores.top_strength || "N/A"} | Weakness: ${scores.primary_weakness || "N/A"} | Voice: ${scores.voice_assessment || "N/A"}`;

const commentText = blocked
  ? `⚠️ Below threshold. ${blockReason}. Composite: ${composite.toFixed(1)}/40 (${qualityTier})`
  : newStatus === "Pre Review"
    ? `✅ Draft evaluated: ${composite.toFixed(1)}/40 (${qualityTier}). Ready for review.`
    : `📝 Draft evaluated: ${composite.toFixed(1)}/40 (${qualityTier}). Below "Good" threshold (28). Consider revising.`;

return [{
  json: {
    pageId: evalData.pageId,
    scores: { clarity, structure, accuracy, credibility, engagement, voice, actionability },
    composite: Math.round(composite * 10) / 10,
    qualityTier,
    newStatus,
    evalNotes,
    commentText,
    blocked,
    blockReason,
    perDimensionFeedback: scores
  }
}];

