// Deduplication guard: prevent re-trigger when pipeline changes status
// Pipeline sets: Draft (Branch A/B output), Published (Branch C output)
// Block these + manual-only statuses that should not trigger the pipeline
const status = $json.status || "";
const blockedStatuses = ["Draft", "Pre Review", "In Review", "Published"];

if (blockedStatuses.includes(status)) {
  // Pipeline-set or non-triggering status — stop execution
  return;
}

// Valid triggers: Idea, Backlog (Branch A), In Revision (Branch B), Publishable (Branch C)
return $input.item;

// Parse execution data to extract pageId and build error comment
const errorTrigger = $('Error Trigger').first().json;
const execData = $input.first().json;  // From Fetch Failed Execution HTTP Request

const errorMessage = errorTrigger.execution?.error?.message || "Unknown error";
const errorNode = errorTrigger.execution?.lastNodeExecuted || "Unknown node";
const executionId = errorTrigger.execution?.id || "N/A";

// Extract pageId from execution runData
let pageId = "";
try {
  const runData = execData.data?.resultData?.runData || {};
  // Try Parse Payload first
  const pp = runData["Parse Payload"];
  if (pp) {
    pageId = pp[0]?.data?.main?.[0]?.[0]?.json?.pageId || "";
  }
  // Try any node with pageId
  if (!pageId) {
    for (const [nodeName, runs] of Object.entries(runData)) {
      const items = runs?.[0]?.data?.main?.[0] || [];
      for (const item of items) {
        if (item?.json?.pageId) {
          pageId = item.json.pageId;
          break;
        }
      }
      if (pageId) break;
    }
  }
} catch(e) { /* best effort */ }

if (!pageId) return [];  // Can't post without a page

const comment = `\u26a0\ufe0f Pipeline Error\n\nNode: ${errorNode}\nError: ${errorMessage}\nExecution: ${executionId}\nTimestamp: ${new Date().toISOString()}`;

return [{json: {
  pageId,
  commentText: comment.substring(0, 1900)
}}];

// Convert Notion blocks to Ghost-compatible HTML and extract page metadata
const page = $('C: Fetch Full Page').first().json;
const blocksResp = $('C: Fetch Page Blocks').first().json;
const blocks = blocksResp.results || [];
const parsePayload = $('Parse Payload').first().json;

// Extract page properties
const props = page.properties || {};

function getTitle(p) {
  if (p && p.title) return p.title.map(t => t.plain_text).join('');
  return '';
}
function getRichText(p) {
  if (p && p.rich_text) return p.rich_text.map(t => t.plain_text).join('');
  return '';
}
function getSelect(p) {
  if (p && p.select) return p.select.name || '';
  if (p && p.status) return p.status.name || '';
  return '';
}
function getUrl(p) {
  if (p && p.url) return p.url || '';
  return '';
}
function getFileUrl(p) {
  if (p && p.files && p.files.length > 0) {
    const f = p.files[0];
    if (f.external) return f.external.url || '';
    if (f.file) return f.file.url || '';
  }
  return '';
}
function getDate(p) {
  if (p && p.date && p.date.start) return p.date.start;
  return '';
}

const title = getTitle(props.Name || props.name || props.Title || props.title);
const pitch = getRichText(props.Pitch || props.pitch || {});
const contentType = getSelect(props['Content Type'] || {});
const dueDatePlanned = getDate(props['Due Date planned'] || props['Due date planned'] || {});
const imageUrl = getFileUrl(props.Image || props.image || {}) || getUrl(props.Image || props.image || {});

// Convert Notion rich_text annotations to HTML
function richTextToHtml(richTexts) {
  if (!richTexts || !richTexts.length) return '';
  return richTexts.map(rt => {
    let text = rt.plain_text || '';
    // Escape HTML entities
    text = text.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
    const ann = rt.annotations || {};
    if (ann.bold) text = '<strong>' + text + '</strong>';
    if (ann.italic) text = '<em>' + text + '</em>';
    if (ann.code) text = '<code>' + text + '</code>';
    if (ann.strikethrough) text = '<s>' + text + '</s>';
    if (rt.href) text = '<a href="' + rt.href + '">' + text + '</a>';
    return text;
  }).join('');
}

// Convert blocks to HTML
let html = '';
let inList = null; // 'ul' or 'ol'

function closeList() {
  if (inList) {
    html += inList === 'ul' ? '</ul>' : '</ol>';
    inList = null;
  }
}

for (const block of blocks) {
  const type = block.type;

  // Skip toggle blocks (they contain previous versions)
  if (type === 'toggle') continue;

  if (type === 'heading_1') {
    closeList();
    html += '<h2>' + richTextToHtml(block.heading_1.rich_text) + '</h2>';
  } else if (type === 'heading_2') {
    closeList();
    html += '<h3>' + richTextToHtml(block.heading_2.rich_text) + '</h3>';
  } else if (type === 'heading_3') {
    closeList();
    html += '<h4>' + richTextToHtml(block.heading_3.rich_text) + '</h4>';
  } else if (type === 'paragraph') {
    closeList();
    const content = richTextToHtml(block.paragraph.rich_text);
    if (content) html += '<p>' + content + '</p>';
  } else if (type === 'bulleted_list_item') {
    if (inList !== 'ul') { closeList(); html += '<ul>'; inList = 'ul'; }
    html += '<li>' + richTextToHtml(block.bulleted_list_item.rich_text) + '</li>';
  } else if (type === 'numbered_list_item') {
    if (inList !== 'ol') { closeList(); html += '<ol>'; inList = 'ol'; }
    html += '<li>' + richTextToHtml(block.numbered_list_item.rich_text) + '</li>';
  } else if (type === 'quote') {
    closeList();
    html += '<blockquote>' + richTextToHtml(block.quote.rich_text) + '</blockquote>';
  } else if (type === 'callout') {
    closeList();
    const icon = block.callout.icon?.emoji || '';
    html += '<blockquote>' + icon + ' ' + richTextToHtml(block.callout.rich_text) + '</blockquote>';
  } else if (type === 'code') {
    closeList();
    const lang = block.code.language || '';
    const code = richTextToHtml(block.code.rich_text);
    html += '<pre><code class="language-' + lang + '">' + code + '</code></pre>';
  } else if (type === 'divider') {
    closeList();
    html += '<hr>';
  } else if (type === 'image') {
    closeList();
    const url = block.image.file?.url || block.image.external?.url || '';
    const caption = block.image.caption ? richTextToHtml(block.image.caption) : '';
    if (url) {
      html += '<figure><img src="' + url + '" alt="' + caption + '">';
      if (caption) html += '<figcaption>' + caption + '</figcaption>';
      html += '</figure>';
    }
  }
}
closeList();

// Map content type to internal Ghost tags
const tagMap = {
  'Opinion': '#opinion',
  'Resource': '#resource',
  'Case Study': '#case-study',
  'Technical': '#technical',
  'Announcement': '#announcement'
};
const tags = [];
if (contentType && tagMap[contentType]) tags.push({name: tagMap[contentType]});
tags.push({name: '#pipeline-generated'});

// Map Notion Category Tags to public Ghost tags (canonical list)
const categoryTags = parsePayload.categoryTags || [];
for (const catTag of categoryTags) {
  // Only pass through canonical tags (ignore legacy format tags)
  const canonical = [
    'AI Models', 'Agents & Automation', 'Context Engineering', 'Dev Tools',
    'Infrastructure', 'Security', 'Industry Moves', 'Regulation', 'Funding',
    'Competitors', 'Strategy', 'Work & Society', 'German Market',
    'MCP', 'Ghost', 'Notion'
  ];
  if (canonical.includes(catTag)) {
    tags.push({name: catTag});
  }
}

// Extract first image from page blocks as fallback feature_image
let blockImageUrl = '';
for (const block of blocks) {
  if (block.type === 'image') {
    const imgUrl = block.image?.file?.url || block.image?.external?.url || '';
    if (imgUrl) {
      blockImageUrl = imgUrl;
      break;
    }
  }
}
// Use Image property first, fall back to first block image
const featureImage = imageUrl || blockImageUrl || '';

return [{json: {
  pageId: parsePayload.pageId,
  title: title,
  pitch: pitch,
  html: html,
  tags: tags,
  contentType: contentType,
  dueDatePlanned: dueDatePlanned,
  imageUrl: featureImage
}}];

const input = $input.first().json;
const parsePayload = $('Parse Payload').first().json;

// Duplicate guard: check if Ghost ID is already set
const existingGhostId = parsePayload.rawProperties?.['Ghost ID']?.rich_text?.[0]?.plain_text || '';
if (existingGhostId) {
  throw new Error('Ghost post already exists (ID: ' + existingGhostId + '). Delete existing post first to re-publish.');
}

// Build post object
const post = {
  title: input.title,
  html: input.html,
  status: 'draft',
  tags: input.tags,
  excerpt: (input.pitch || '').substring(0, 300) || undefined,
  feature_image: input.imageUrl || undefined,
  meta_title: (input.title || '').substring(0, 60) || undefined,
  meta_description: (input.pitch || '').substring(0, 155) || undefined,
  newsletter: { slug: 'default-newsletter' }
};

// If due date is set, schedule it
if (input.dueDatePlanned) {
  const dueDate = new Date(input.dueDatePlanned + 'T12:00:00Z');
  const month = dueDate.getMonth();
  const isCEST = month >= 2 && month <= 9;
  const offset = isCEST ? '+02:00' : '+01:00';
  const scheduleDate = new Date(input.dueDatePlanned + 'T09:00:00' + offset);
  if (scheduleDate > new Date()) {
    post.status = 'scheduled';
    post.published_at = scheduleDate.toISOString();
  }
}

return [{json: {
  ghostPayload: { posts: [post] },
  pageId: input.pageId,
  title: input.title
}}];

// Assemble revision context: feedback + current draft + brand context
const parsePayload = $('Parse Payload').first().json;
const commentsResp = $('B: Fetch Feedback').first().json;
const blocksResp = $('B: Fetch Draft Blocks').first().json;
const brandResp = $('B: Fetch Writing Guide').first().json;

// Extract feedback comments (filter to human comments, skip bot/pipeline comments)
const comments = (commentsResp.results || [])
  .filter(c => {
    const text = (c.rich_text || []).map(t => t.plain_text).join('');
    // Skip pipeline-generated comments
    if (text.startsWith('✅') || text.startsWith('📊') || text.startsWith('🔄') || text.startsWith('❌')) return false;
    return true;
  })
  .map(c => (c.rich_text || []).map(t => t.plain_text).join(''))
  .filter(t => t.length > 0);

const feedbackText = comments.length > 0
  ? comments.join('\n\n---\n\n')
  : 'No specific feedback provided. Please improve the draft based on the evaluation scores.';

// Convert current draft blocks to markdown for context
const blocks = blocksResp.results || [];
let draftText = '';
for (const block of blocks) {
  const type = block.type;
  if (type === 'paragraph') {
    draftText += (block.paragraph.rich_text || []).map(t => t.plain_text).join('') + '\n\n';
  } else if (type === 'heading_1') {
    draftText += '# ' + (block.heading_1.rich_text || []).map(t => t.plain_text).join('') + '\n\n';
  } else if (type === 'heading_2') {
    draftText += '## ' + (block.heading_2.rich_text || []).map(t => t.plain_text).join('') + '\n\n';
  } else if (type === 'heading_3') {
    draftText += '### ' + (block.heading_3.rich_text || []).map(t => t.plain_text).join('') + '\n\n';
  } else if (type === 'bulleted_list_item') {
    draftText += '- ' + (block.bulleted_list_item.rich_text || []).map(t => t.plain_text).join('') + '\n';
  } else if (type === 'numbered_list_item') {
    draftText += '1. ' + (block.numbered_list_item.rich_text || []).map(t => t.plain_text).join('') + '\n';
  } else if (type === 'quote') {
    draftText += '> ' + (block.quote.rich_text || []).map(t => t.plain_text).join('') + '\n\n';
  } else if (type === 'divider') {
    draftText += '---\n\n';
  }
}

// Extract brand context as text
const brandBlocks = brandResp.results || [];
let brandText = '';
for (const block of brandBlocks) {
  if (block.type === 'paragraph') {
    brandText += (block.paragraph.rich_text || []).map(t => t.plain_text).join('') + '\n';
  }
}

return [{json: {
  pageId: parsePayload.pageId,
  name: parsePayload.name,
  pitch: parsePayload.pitch,
  feedbackText: feedbackText,
  currentDraft: draftText.trim(),
  brandContext: brandText.trim(),
  commentCount: comments.length,
  blockIds: blocks.map(b => b.id)  // For archiving old blocks
}}];

// Archive old blocks into a toggle and prepare for redraft
// This node outputs the data needed for the HTTP calls that follow
const input = $input.first().json;

// We'll delete old blocks and create a toggle with archived content
// Then the draft agent (reusing Branch A) will append new content

// Count existing revisions by looking at toggle blocks named "Previous Version"
// For now, just mark this as revision v2+

return [{json: {
  pageId: input.pageId,
  name: input.name,
  pitch: input.pitch,
  feedbackText: input.feedbackText,
  currentDraft: input.currentDraft,
  brandContext: input.brandContext,
  blockIds: input.blockIds,
  // System prompt for revision
  systemPrompt: `You are revising a blog post draft for T-0, a German AI consultancy.

## Brand Voice Context
${input.brandContext}

## Current Draft
${input.currentDraft}

## Editor Feedback
${input.feedbackText}

## Instructions
1. Address ALL feedback points explicitly
2. Maintain the same structure unless feedback specifically requests changes
3. Keep the T-0 voice: confident but not arrogant, practical, German market focus
4. Output the revised draft in markdown format
5. Include a <!-- META revision:true feedback_points_addressed:N --> comment at the end

Write the complete revised article in German. Do not truncate or summarize — output the full revised draft.`
}}];

const httpResp = $input.first().json;
const buildPayload = $('C: Build Ghost Payload').first().json;

// Ghost API returns { posts: [{ id, url, slug, status, ... }] }
const createdPost = httpResp.posts?.[0];
if (!createdPost) {
  throw new Error('Ghost API did not return a post: ' + JSON.stringify(httpResp).substring(0, 500));
}

return [{json: {
  pageId: buildPayload.pageId,
  ghostId: createdPost.id,
  ghostUrl: createdPost.url,
  ghostStatus: createdPost.status,
  ghostSlug: createdPost.slug,
  title: buildPayload.title
}}];

// Prepare individual items for block deletion
const input = $input.first().json;
const blockIds = input.blockIds || [];

// Output one item per blockId for the HTTP Request to process
const items = blockIds.map(id => ({json: {blockId: id}}));

// If no blocks to delete, output empty to skip
if (items.length === 0) {
  return [{json: {blockId: '_skip_'}}];
}
return items;

// Build archive toggle and pass through data
const input = $('B: Archive & Redraft').first().json;
const pageId = input.pageId;
const currentDraft = input.currentDraft || '';

const archiveChildren = [
  {
    type: 'toggle',
    toggle: {
      rich_text: [{ text: { content: '\u{1F4E6} Previous Version (pre-revision)' } }],
      children: [
        {
          type: 'paragraph',
          paragraph: {
            rich_text: [{ text: { content: currentDraft.substring(0, 2000) } }]
          }
        }
      ]
    }
  },
  { type: 'divider', divider: {} }
];

return [{json: {
  archiveBody: JSON.stringify({ children: archiveChildren }),
  pageId: pageId,
  name: input.name,
  pitch: input.pitch,
  systemPrompt: input.systemPrompt,
  feedbackText: input.feedbackText,
  brandContext: input.brandContext
}}];

// Pass through data for downstream revision generation
const archive = $('B: Build Archive').first().json;
return [{json: {
  pageId: archive.pageId,
  name: archive.name,
  pitch: archive.pitch,
  systemPrompt: archive.systemPrompt,
  feedbackText: archive.feedbackText,
  brandContext: archive.brandContext
}}];

const input = $('B: Pass Delete Data').first().json;
const draft = $('B: Generate Revised Draft').first().json;
const draftText = draft.output || draft.text || '';
const pageId = input.pageId;

// Convert markdown to Notion blocks with inline formatting
function parseInlineFormatting(text) {
  const segments = [];
  const pattern = /(\*\*(.+?)\*\*|\*(.+?)\*|`(.+?)`|\[(.+?)\]\((.+?)\))/g;
  let lastIndex = 0;
  let match;
  while ((match = pattern.exec(text)) !== null) {
    if (match.index > lastIndex) {
      segments.push({ text: { content: text.slice(lastIndex, match.index) } });
    }
    if (match[2]) { segments.push({ text: { content: match[2] }, annotations: { bold: true } }); }
    else if (match[3]) { segments.push({ text: { content: match[3] }, annotations: { italic: true } }); }
    else if (match[4]) { segments.push({ text: { content: match[4] }, annotations: { code: true } }); }
    else if (match[5] && match[6]) { segments.push({ text: { content: match[5], link: { url: match[6] } } }); }
    lastIndex = match.index + match[0].length;
  }
  if (lastIndex < text.length) { segments.push({ text: { content: text.slice(lastIndex) } }); }
  if (segments.length === 0) { segments.push({ text: { content: text } }); }
  return segments;
}

const lines = draftText.split('\n');
const blocks = [];
let inCodeFence = false;
let codeLines = [];
let codeLang = '';

for (let line of lines) {
  if (line.trim().startsWith('```')) {
    if (inCodeFence) {
      blocks.push({ type: 'code', code: { rich_text: [{ text: { content: codeLines.join('\n') } }], language: codeLang || 'plain text' } });
      inCodeFence = false; codeLines = []; codeLang = '';
      continue;
    } else { inCodeFence = true; codeLang = line.trim().slice(3).trim(); continue; }
  }
  if (inCodeFence) { codeLines.push(line); continue; }
  line = line.trim();
  if (!line) continue;
  if (line.startsWith('<!--') && line.includes('META')) continue;

  if (line.startsWith('# ')) { blocks.push({ type: 'heading_1', heading_1: { rich_text: parseInlineFormatting(line.slice(2).trim()) } }); }
  else if (line.startsWith('## ')) { blocks.push({ type: 'heading_2', heading_2: { rich_text: parseInlineFormatting(line.slice(3).trim()) } }); }
  else if (line.startsWith('### ')) { blocks.push({ type: 'heading_3', heading_3: { rich_text: parseInlineFormatting(line.slice(4).trim()) } }); }
  else if (line.startsWith('- ') || line.startsWith('* ')) { blocks.push({ type: 'bulleted_list_item', bulleted_list_item: { rich_text: parseInlineFormatting(line.slice(2).trim()) } }); }
  else if (line.match(/^\d+\.\s/)) { blocks.push({ type: 'numbered_list_item', numbered_list_item: { rich_text: parseInlineFormatting(line.replace(/^\d+\.\s/, '').trim()) } }); }
  else if (line.startsWith('> ')) { blocks.push({ type: 'quote', quote: { rich_text: parseInlineFormatting(line.slice(2).trim()) } }); }
  else if (line === '---') { blocks.push({ type: 'divider', divider: {} }); }
  else { blocks.push({ type: 'paragraph', paragraph: { rich_text: parseInlineFormatting(line) } }); }
}

if (inCodeFence && codeLines.length > 0) {
  blocks.push({ type: 'code', code: { rich_text: [{ text: { content: codeLines.join('\n') } }], language: codeLang || 'plain text' } });
}

// Sanitize: split >2000 char content
for (const block of blocks) {
  const btype = block.type;
  if (block[btype] && block[btype].rich_text) {
    const sanitized = [];
    for (const rt of block[btype].rich_text) {
      const content = rt.text ? rt.text.content || '' : '';
      if (content.length <= 2000) { sanitized.push(rt); }
      else { for (let ci = 0; ci < content.length; ci += 2000) {
        const chunk = { text: { content: content.slice(ci, ci + 2000) } };
        if (rt.text && rt.text.link) chunk.text.link = rt.text.link;
        if (rt.annotations) chunk.annotations = Object.assign({}, rt.annotations);
        sanitized.push(chunk);
      }}
    }
    block[btype].rich_text = sanitized;
  }
}

// Split into batches of 100 — output one item per batch
const batchSize = 100;
const items = [];
for (let i = 0; i < blocks.length; i += batchSize) {
  const batch = blocks.slice(i, i + batchSize);
  items.push({json: {
    batchBody: JSON.stringify({ children: batch }),
    pageId: pageId,
    batchIndex: Math.floor(i / batchSize),
    totalBlocks: blocks.length
  }});
}

if (items.length === 0) {
  items.push({json: { batchBody: JSON.stringify({ children: [] }), pageId: pageId, batchIndex: 0, totalBlocks: 0 }});
}

return items;

// Build revision comment — run once, reference upstream for data
const parseData = $('B: Parse Draft Blocks').first().json;
const pageId = parseData.pageId;
const totalBlocks = parseData.totalBlocks;
const draft = $('B: Generate Revised Draft').first().json;
const draftText = draft.output || draft.text || '';
const contentType = $('Parse Payload').first().json.contentType || '';

return [{json: {
  commentBody: JSON.stringify({
    parent: { page_id: pageId },
    rich_text: [{ text: { content: '\u{1F504} Revision complete. ' + totalBlocks + ' blocks written. Running re-evaluation...' } }]
  }),
  pageId: pageId,
  blocksWritten: totalBlocks,
  cleanDraft: draftText,
  contentType: contentType,
  status: 'revised'
}}];

// Final revision output for downstream
const data = $('B: Prepare Comment').first().json;
return [{json: {
  pageId: data.pageId,
  blocksWritten: data.blocksWritten,
  cleanDraft: data.cleanDraft,
  contentType: data.contentType,
  status: data.status
}}];

// Parse Notion automation payload
const input = $input.first().json;
const body = input.body || input;
const pageData = body.data || body;
const props = pageData.properties || {};

const pageId = (pageData.id || "").replace(/-/g, "");
if (!pageId) throw new Error("No page ID in payload");

let status = "";
if (props.Status) {
  status = props.Status.status?.name || props.Status.select?.name || "";
}

let name = "";
if (props.Name && props.Name.title) {
  name = props.Name.title.map(t => t.plain_text || "").join("");
}

let pitch = "";
if (props.Pitch && props.Pitch.rich_text) {
  pitch = props.Pitch.rich_text.map(t => t.plain_text || "").join("");
}

let url = "";
if (props.URL) { url = props.URL.url || ""; }

let dueDate = "";
if (props["Due Date planned"] && props["Due Date planned"].date) {
  dueDate = props["Due Date planned"].date.start || "";
}

let contentType = "";
if (props["Content Type"] && props["Content Type"].select) {
  contentType = props["Content Type"].select.name || "";
}

let imageUrl = "";
if (props.Image && props.Image.files && props.Image.files.length > 0) {
  const f = props.Image.files[0];
  imageUrl = f.file?.url || f.external?.url || f.name || "";
}

let categoryTags = [];
if (props["Category Tags"] && props["Category Tags"].multi_select) {
  categoryTags = props["Category Tags"].multi_select.map(t => t.name);
}

let notesRelationIds = [];
if (props.Notes && props.Notes.relation) {
  notesRelationIds = props.Notes.relation.map(r => r.id);
}

let imageGenDesc = "";
if (props["Image Gen Description"] && props["Image Gen Description"].rich_text) {
  imageGenDesc = props["Image Gen Description"].rich_text.map(t => t.plain_text || "").join("");
}

return [{
  json: {
    pageId, status, name, pitch, url, dueDate, contentType,
    imageUrl, categoryTags, notesRelationIds, imageGenDesc,
    rawProperties: props
  }
}];

// Convert Notion blocks to markdown and merge brand context
function blocksToMd(blocks) {
  if (!blocks || !Array.isArray(blocks)) return "";
  return blocks.map(b => {
    const type = b.type;
    if (type === "divider") return "---";
    const rt = b[type]?.rich_text || [];
    const text = rt.map(r => {
      let t = r.plain_text || "";
      if (r.annotations?.bold) t = `**${t}**`;
      if (r.annotations?.italic) t = `*${t}*`;
      if (r.annotations?.code) t = "`" + t + "`";
      if (r.href) t = `[${t}](${r.href})`;
      return t;
    }).join("");
    if (type === "heading_1") return `# ${text}`;
    if (type === "heading_2") return `## ${text}`;
    if (type === "heading_3") return `### ${text}`;
    if (type === "bulleted_list_item") return `- ${text}`;
    if (type === "numbered_list_item") return `1. ${text}`;
    if (type === "quote") return `> ${text}`;
    if (type === "callout") return `> ${text}`;
    if (type === "code") return "```\n" + text + "\n```";
    return text;
  }).filter(l => l.trim() !== "").join("\n");
}

// Items arrive appended from Merge node — access by index
const items = $input.all();
const writingGuide = blocksToMd(items[0]?.json?.results || []);
const contentGuide = blocksToMd(items[1]?.json?.results || []);
const styleAnalysis = blocksToMd(items[2]?.json?.results || []);
const pageData = $('Parse Payload').first().json;

return [{
  json: {
    ...pageData,
    brandContext: {
      writingGuide: writingGuide.substring(0, 8000),
      contentGuide: contentGuide.substring(0, 8000),
      styleAnalysis: styleAnalysis.substring(0, 4000)
    }
  }
}];

// Merge brand context + pipeline config + parse YAML style params
const brandData = $('Merge Brand Context').first().json;

// Items from the config merge
const configItems = $input.all();
const draftPromptRaw = configItems[0]?.json?.data || configItems[0]?.json?.body || JSON.stringify(configItems[0]?.json || "");
const styleParamsRaw = configItems[1]?.json?.data || configItems[1]?.json?.body || JSON.stringify(configItems[1]?.json || "");

// Simple YAML parser for style-params.yaml
function parseSimpleYaml(text) {
  const result = {};
  let currentSection = null;
  let currentSubSection = null;
  for (const line of text.split("\n")) {
    if (line.startsWith("#") || line.trim() === "") continue;
    const sectionMatch = line.match(/^(\w+):$/);
    if (sectionMatch) { currentSection = sectionMatch[1]; result[currentSection] = {}; currentSubSection = null; continue; }
    const subSectionMatch = line.match(/^  (\w+):$/);
    if (subSectionMatch && currentSection) { currentSubSection = subSectionMatch[1]; result[currentSection][currentSubSection] = {}; continue; }
    const kvMatch = line.match(/^\s+(\w+):\s+(.+)$/);
    if (kvMatch) {
      let val = kvMatch[2].trim();
      if (val === "true") val = true;
      else if (val === "false") val = false;
      else if (/^[\d.]+$/.test(val)) val = parseFloat(val);
      else val = val.replace(/^["']|["']$/g, "");
      if (currentSubSection && currentSection) {
        result[currentSection][currentSubSection][kvMatch[1]] = val;
      } else if (currentSection) {
        result[currentSection][kvMatch[1]] = val;
      }
    }
  }
  return result;
}

const styleParams = parseSimpleYaml(typeof styleParamsRaw === "string" ? styleParamsRaw : "");

function weightedPick(patterns) {
  if (!patterns) return "concrete_scenario";
  const entries = Object.entries(patterns);
  const total = entries.reduce((s, [, w]) => s + (typeof w === "number" ? w : 0), 0);
  let r = Math.random() * total;
  for (const [name, weight] of entries) {
    r -= (typeof weight === "number" ? weight : 0);
    if (r <= 0) return name;
  }
  return entries[0]?.[0] || "concrete_scenario";
}

const openingPattern = weightedPick(styleParams.opening?.preferred_patterns);
const closingPattern = weightedPick(styleParams.closing?.preferred_patterns);

return [{
  json: {
    ...brandData,
    draftPromptTemplate: typeof draftPromptRaw === "string" ? draftPromptRaw : "",
    styleParams,
    openingPattern,
    closingPattern
  }
}];

