// Detect content type + assemble draft prompt
const ctx = $('Merge All Context').first().json;
const research = $('Research Agent').first().json;
const researchText = research.output || research.text || JSON.stringify(research);

// Detect content type if not set
let contentType = ctx.contentType;
if (!contentType) {
  const combined = (ctx.name + " " + ctx.pitch + " " + researchText).toLowerCase();
  if (combined.includes("case study") || combined.includes("projekt") || combined.includes("kundenbeispiel")) {
    contentType = "Case Study";
  } else if (combined.includes("how to") || combined.includes("anleitung") || combined.includes("tutorial") || combined.includes("guide")) {
    contentType = "Resource";
  } else if (combined.includes("technisch") || combined.includes("api") || combined.includes("implementation") || combined.includes("code")) {
    contentType = "Technical";
  } else if (combined.includes("ankündigung") || combined.includes("announcement") || combined.includes("launch")) {
    contentType = "Announcement";
  } else {
    contentType = "Opinion";
  }
}

const sp = ctx.styleParams || {};
const voice = sp.voice || {};
const structure = sp.structure || {};
const targetWords = structure.target_word_count?.[contentType.toLowerCase()] || 1500;

// Assemble system prompt
let systemPrompt = ctx.draftPromptTemplate || "";
systemPrompt = systemPrompt
  .replace("{brand_writing_guide_voice_section}", ctx.brandContext?.writingGuide || "")
  .replace("{blog_content_guide_template_for_{content_type}}", ctx.brandContext?.contentGuide || "")
  .replace("{blog_style_research_summary}", (ctx.brandContext?.styleAnalysis || "").substring(0, 2000))
  .replace("{opinion_strength}", String(voice.opinion_strength || 0.8))
  .replace("{personal_anecdote_required}", String(voice.personal_anecdote_required ?? true))
  .replace("{target_word_count}", String(targetWords))
  .replace("{opening_pattern}", ctx.openingPattern || "concrete_scenario")
  .replace("{closing_pattern}", ctx.closingPattern || "actionable_next_step")
  .replace("{banned_terms_list}", "leverage, game-changer, cutting-edge, revolutionär, bahnbrechend, Paradigmenwechsel");

// Assemble user prompt
let userPrompt = `## Thema: ${ctx.name}\n\n`;
if (ctx.pitch) userPrompt += `## Pitch: ${ctx.pitch}\n\n`;
userPrompt += `## Content Type: ${contentType}\n\n`;
userPrompt += `## Ziel-Wortanzahl: ${targetWords}\n\n`;
userPrompt += `## Öffnungsmuster: ${ctx.openingPattern}\n## Schlussmuster: ${ctx.closingPattern}\n\n`;
userPrompt += `## Recherche-Ergebnisse:\n\n${researchText}\n\n`;
userPrompt += `Schreibe jetzt den vollständigen Blogpost auf Deutsch.`;

return [{
  json: {
    ...ctx,
    contentType,
    researchText,
    systemPrompt: systemPrompt.substring(0, 12000),
    userPrompt: userPrompt.substring(0, 8000)
  }
}];

// Parse draft, convert to Notion blocks, prepare API calls
const ctx = $('Assemble Draft Prompt').first().json;
const draft = $('Generate Draft').first().json;
const draftText = draft.output || draft.text || "";

// Extract META comment
let meta = {};
const metaMatch = draftText.match(/<!--\s*META\s*([\s\S]*?)-->/);
if (metaMatch) {
  for (const line of metaMatch[1].split("\n")) {
    const kv = line.match(/(\w+):\s*(.+)/);
    if (kv) meta[kv[1].trim()] = kv[2].trim();
  }
}

// Clean draft (remove META comment)
const cleanDraft = draftText.replace(/<!--\s*META[\s\S]*?-->/, "").trim();

// Convert Markdown to Notion blocks
function mdToBlocks(md) {
  const blocks = [];
  const lines = md.split("\n");
  let inCodeBlock = false;
  let codeContent = "";
  let codeLang = "";

  for (const line of lines) {
    if (line.startsWith("```")) {
      if (inCodeBlock) {
        blocks.push({type: "code", code: {rich_text: [{type: "text", text: {content: codeContent.trim()}}], language: codeLang || "plain text"}});
        inCodeBlock = false; codeContent = ""; codeLang = "";
      } else {
        inCodeBlock = true; codeLang = line.slice(3).trim();
      }
      continue;
    }
    if (inCodeBlock) { codeContent += line + "\n"; continue; }
    if (line.trim() === "") continue;
    if (line.trim() === "---") { blocks.push({type: "divider", divider: {}}); continue; }

    // Parse inline formatting
    function parseRichText(text) {
      const parts = [];
      // Simple approach: split on markdown patterns
      let remaining = text;
      while (remaining.length > 0) {
        // Bold
        const boldMatch = remaining.match(/\*\*(.+?)\*\*/);
        if (boldMatch && boldMatch.index === 0) {
          parts.push({type: "text", text: {content: boldMatch[1]}, annotations: {bold: true}});
          remaining = remaining.slice(boldMatch[0].length);
          continue;
        }
        // Italic
        const italicMatch = remaining.match(/\*(.+?)\*/);
        if (italicMatch && italicMatch.index === 0) {
          parts.push({type: "text", text: {content: italicMatch[1]}, annotations: {italic: true}});
          remaining = remaining.slice(italicMatch[0].length);
          continue;
        }
        // Link
        const linkMatch = remaining.match(/\[(.+?)\]\((.+?)\)/);
        if (linkMatch && linkMatch.index === 0) {
          parts.push({type: "text", text: {content: linkMatch[1], link: {url: linkMatch[2]}}});
          remaining = remaining.slice(linkMatch[0].length);
          continue;
        }
        // Inline code
        const codeMatch = remaining.match(/`(.+?)`/);
        if (codeMatch && codeMatch.index === 0) {
          parts.push({type: "text", text: {content: codeMatch[1]}, annotations: {code: true}});
          remaining = remaining.slice(codeMatch[0].length);
          continue;
        }
        // Plain text until next special char
        const nextSpecial = remaining.search(/[\*\[\`]/);
        if (nextSpecial > 0) {
          parts.push({type: "text", text: {content: remaining.slice(0, nextSpecial)}});
          remaining = remaining.slice(nextSpecial);
        } else {
          parts.push({type: "text", text: {content: remaining}});
          remaining = "";
        }
      }
      return parts.length > 0 ? parts : [{type: "text", text: {content: text}}];
    }

    if (line.startsWith("### ")) {
      blocks.push({type: "heading_3", heading_3: {rich_text: parseRichText(line.slice(4))}});
    } else if (line.startsWith("## ")) {
      blocks.push({type: "heading_2", heading_2: {rich_text: parseRichText(line.slice(3))}});
    } else if (line.startsWith("# ")) {
      blocks.push({type: "heading_2", heading_2: {rich_text: parseRichText(line.slice(2))}});
    } else if (line.startsWith("- ") || line.startsWith("* ")) {
      blocks.push({type: "bulleted_list_item", bulleted_list_item: {rich_text: parseRichText(line.slice(2))}});
    } else if (/^\d+\.\s/.test(line)) {
      blocks.push({type: "numbered_list_item", numbered_list_item: {rich_text: parseRichText(line.replace(/^\d+\.\s/, ""))}});
    } else if (line.startsWith("> ")) {
      blocks.push({type: "quote", quote: {rich_text: parseRichText(line.slice(2))}});
    } else {
      blocks.push({type: "paragraph", paragraph: {rich_text: parseRichText(line)}});
    }
  }
  return blocks;
}

const blocks = mdToBlocks(cleanDraft);

// Batch blocks into groups of 100
const batches = [];
for (let i = 0; i < blocks.length; i += 100) {
  batches.push(blocks.slice(i, i + 100));
}

return [{
  json: {
    pageId: ctx.pageId,
    contentType: ctx.contentType,
    cleanDraft,
    meta,
    blocks,
    batches,
    batchCount: batches.length,
    researchText: ctx.researchText
  }
}];

