const input = $('B: Pass Delete Data').first().json;
const draft = $('B: Generate Revised Draft').first().json;
const draftText = draft.output || draft.text || '';
const pageId = input.pageId;

// Convert markdown to Notion blocks with inline formatting
function parseInlineFormatting(text) {
  const segments = [];
  const pattern = /(\*\*(.+?)\*\*|\*(.+?)\*|`(.+?)`|\[(.+?)\]\((.+?)\))/g;
  let lastIndex = 0;
  let match;
  while ((match = pattern.exec(text)) !== null) {
    if (match.index > lastIndex) {
      segments.push({ text: { content: text.slice(lastIndex, match.index) } });
    }
    if (match[2]) { segments.push({ text: { content: match[2] }, annotations: { bold: true } }); }
    else if (match[3]) { segments.push({ text: { content: match[3] }, annotations: { italic: true } }); }
    else if (match[4]) { segments.push({ text: { content: match[4] }, annotations: { code: true } }); }
    else if (match[5] && match[6]) { segments.push({ text: { content: match[5], link: { url: match[6] } } }); }
    lastIndex = match.index + match[0].length;
  }
  if (lastIndex < text.length) { segments.push({ text: { content: text.slice(lastIndex) } }); }
  if (segments.length === 0) { segments.push({ text: { content: text } }); }
  return segments;
}

const lines = draftText.split('\n');
const blocks = [];
let inCodeFence = false;
let codeLines = [];
let codeLang = '';

for (let line of lines) {
  if (line.trim().startsWith('```')) {
    if (inCodeFence) {
      blocks.push({ type: 'code', code: { rich_text: [{ text: { content: codeLines.join('\n') } }], language: codeLang || 'plain text' } });
      inCodeFence = false; codeLines = []; codeLang = '';
      continue;
    } else { inCodeFence = true; codeLang = line.trim().slice(3).trim(); continue; }
  }
  if (inCodeFence) { codeLines.push(line); continue; }
  line = line.trim();
  if (!line) continue;
  if (line.startsWith('<!--') && line.includes('META')) continue;

  if (line.startsWith('# ')) { blocks.push({ type: 'heading_1', heading_1: { rich_text: parseInlineFormatting(line.slice(2).trim()) } }); }
  else if (line.startsWith('## ')) { blocks.push({ type: 'heading_2', heading_2: { rich_text: parseInlineFormatting(line.slice(3).trim()) } }); }
  else if (line.startsWith('### ')) { blocks.push({ type: 'heading_3', heading_3: { rich_text: parseInlineFormatting(line.slice(4).trim()) } }); }
  else if (line.startsWith('- ') || line.startsWith('* ')) { blocks.push({ type: 'bulleted_list_item', bulleted_list_item: { rich_text: parseInlineFormatting(line.slice(2).trim()) } }); }
  else if (line.match(/^\d+\.\s/)) { blocks.push({ type: 'numbered_list_item', numbered_list_item: { rich_text: parseInlineFormatting(line.replace(/^\d+\.\s/, '').trim()) } }); }
  else if (line.startsWith('> ')) { blocks.push({ type: 'quote', quote: { rich_text: parseInlineFormatting(line.slice(2).trim()) } }); }
  else if (line === '---') { blocks.push({ type: 'divider', divider: {} }); }
  else { blocks.push({ type: 'paragraph', paragraph: { rich_text: parseInlineFormatting(line) } }); }
}

if (inCodeFence && codeLines.length > 0) {
  blocks.push({ type: 'code', code: { rich_text: [{ text: { content: codeLines.join('\n') } }], language: codeLang || 'plain text' } });
}

// Sanitize: split >2000 char content
for (const block of blocks) {
  const btype = block.type;
  if (block[btype] && block[btype].rich_text) {
    const sanitized = [];
    for (const rt of block[btype].rich_text) {
      const content = rt.text ? rt.text.content || '' : '';
      if (content.length <= 2000) { sanitized.push(rt); }
      else { for (let ci = 0; ci < content.length; ci += 2000) {
        const chunk = { text: { content: content.slice(ci, ci + 2000) } };
        if (rt.text && rt.text.link) chunk.text.link = rt.text.link;
        if (rt.annotations) chunk.annotations = Object.assign({}, rt.annotations);
        sanitized.push(chunk);
      }}
    }
    block[btype].rich_text = sanitized;
  }
}

// Split into batches of 100 — output one item per batch
const batchSize = 100;
const items = [];
for (let i = 0; i < blocks.length; i += batchSize) {
  const batch = blocks.slice(i, i + batchSize);
  items.push({json: {
    batchBody: JSON.stringify({ children: batch }),
    pageId: pageId,
    batchIndex: Math.floor(i / batchSize),
    totalBlocks: blocks.length
  }});
}

if (items.length === 0) {
  items.push({json: { batchBody: JSON.stringify({ children: [] }), pageId: pageId, batchIndex: 0, totalBlocks: 0 }});
}

return items;

// Build revision comment — run once, reference upstream for data
